    Find the shortest path between two nodes in a weighted graph.

    Parameters:
    graph (dict): A dictionary representing the graph where keys are nodes and values are dictionaries of adjacent nodes and weights.
    start (str): The starting node of the path.
    end (str): The ending node of the path.

    Returns:
    list: A list of nodes representing the shortest path from start to end.
    """
    if start == end:
        return [start]

    shortest_path = None
    for neighbor in graph[start]:
        if neighbor not in shortest_path:
            shortest_path = shortest_path(graph, start, neighbor)
            if shortest_path:
                break
        else:
            if shortest_path is None:
                shortest_path = [neighbor]
            else:
                shortest_path.append(neighbor)

    return shortest_path

